114	function is_alnum(c: char): boolean;
115	begin is_alnum := is_digit(c) or is_alpha(c) or (c = chr(39)) end;
116	function is_space(c: char): boolean;
117	begin is_space := (c = ' ') or (c = chr(9)) or (c = chr(10)) or (c = chr(13)) end;
