  OP_LE=38; OP_GE=39; OP_AND=40; OP_OR=41; OP_NOT=19;
  OP_CONS=55; OP_PAIR=56; OP_CONCAT=57;
  NAME_POOL_MAX=2048;
  VK_INT=1; VK_BOOL=2; VK_CLOSURE=3; VK_UNIT=4;
  VK_NIL=5; VK_CONS=6; VK_PAIR=7;
  VK_NONE=8; VK_SOME=9; VK_STRING=10;

type
  PPat = ^Pat;
  PExpr = ^Expr;
  Expr = record
    kind: integer; ival: integer; op: integer;
    noff: integer; nlen: integer;
    left: PExpr; right: PExpr; extra: PExpr;
    pat: PPat
  end;
  Pat = record
    pk: integer;
    ival: integer;
    noff: integer; nlen: integer;
    sub1: PPat; sub2: PPat
  end;
  PEnv = ^EnvEntry;
  PVal = ^Val;
  Val = record
    vk: integer; ival: integer;
    noff: integer; nlen: integer;
    body: PExpr; cenv: PEnv;
    head: PVal; tail: PVal
  end;
  EnvEntry = record
    noff: integer; nlen: integer;
    val: PVal; next: PEnv
  end;

var
  tok: integer; tok_int: integer;
  tok_id: array[0..63] of char; tok_id_len: integer;
  src: array[0..4095] of char; src_len: integer;
  pos: integer; ch: char;
  name_pool: array[0..2047] of char; name_pool_len: integer;
  string_pool: array[0..4095] of char; string_pool_len: integer;
  tok_str_off: integer; tok_str_len: integer;
  parse_error: boolean; eval_error: boolean;
  match_success: boolean;
  print_int_noff: integer; print_int_nlen: integer;
  set_led_noff: integer; set_led_nlen: integer;
  led_on_noff: integer; led_on_nlen: integer;
  led_off_noff: integer; led_off_nlen: integer;
  switch_noff: integer; switch_nlen: integer;
  putc_noff: integer; putc_nlen: integer;
  putc_ch: char;
  wildcard_noff: integer; wildcard_nlen: integer;
  nil_noff: integer; nil_nlen: integer;
  hd_noff: integer; hd_nlen: integer;
  tl_noff: integer; tl_nlen: integer;
  isempty_noff: integer; isempty_nlen: integer;
  list_length_noff: integer; list_length_nlen: integer;
  list_rev_noff: integer; list_rev_nlen: integer;
  list_hd_noff: integer; list_hd_nlen: integer;
  list_tl_noff: integer; list_tl_nlen: integer;
  list_isempty_noff: integer; list_isempty_nlen: integer;
  fst_noff: integer; fst_nlen: integer;
  snd_noff: integer; snd_nlen: integer;
  none_noff: integer; none_nlen: integer;
  some_noff: integer; some_nlen: integer;
  fn_arg_noff: integer; fn_arg_nlen: integer;
  let_tmp_noff: integer; let_tmp_nlen: integer;
  print_endline_noff: integer; print_endline_nlen: integer;
  string_length_noff: integer; string_length_nlen: integer;
  ast: PExpr; result: PVal;

function pool_intern: integer;
var start, j: integer;
begin start := name_pool_len; j := 0;
  while j < tok_id_len do begin
    if name_pool_len < NAME_POOL_MAX then begin name_pool[name_pool_len] := tok_id[j]; name_pool_len := name_pool_len + 1 end;
    j := j + 1 end;
  pool_intern := start end;

{ === Lexer === }
function is_digit(c: char): boolean;
begin is_digit := (c >= '0') and (c <= '9') end;
function is_alpha(c: char): boolean;
begin is_alpha := ((c >= 'a') and (c <= 'z')) or ((c >= 'A') and (c <= 'Z')) or (c = '_') end;
function is_alnum(c: char): boolean;
begin is_alnum := is_digit(c) or is_alpha(c) or (c = chr(39)) end;
function is_space(c: char): boolean;
begin is_space := (c = ' ') or (c = chr(9)) or (c = chr(10)) or (c = chr(13)) end;
procedure skip_whitespace;
begin while (pos < src_len) and is_space(src[pos]) do pos := pos + 1 end;
function skip_comment: boolean;
var depth: integer;
begin skip_comment := false;
  if (pos+1 < src_len) and (src[pos] = '(') and (src[pos+1] = '*') then begin
    pos := pos+2; depth := 1;
    while (pos+1 < src_len) and (depth > 0) do begin
      if (src[pos] = '(') and (src[pos+1] = '*') then begin depth := depth+1; pos := pos+2 end
      else if (src[pos] = '*') and (src[pos+1] = ')') then begin depth := depth-1; pos := pos+2 end
      else pos := pos+1 end;
    skip_comment := true end end;
procedure skip_ws_and_comments;

content.content:
130	procedure skip_ws_and_comments;
131	var moved: boolean;
132	begin repeat moved := false; skip_whitespace; if skip_comment then moved := true until not moved end;
133	function classify_ident: integer;
134	begin classify_ident := TK_IDENT;
135	  if tok_id_len = 2 then begin
136	    if (tok_id[0]='i') and (tok_id[1]='f') then classify_ident := TK_IF
137	    else if (tok_id[0]='i') and (tok_id[1]='n') then classify_ident := TK_IN
138	  end else if tok_id_len = 3 then begin
139	    if (tok_id[0]='l') and (tok_id[1]='e') and (tok_id[2]='t') then classify_ident := TK_LET
140	    else if (tok_id[0]='r') and (tok_id[1]='e') and (tok_id[2]='c') then classify_ident := TK_REC
141	    else if (tok_id[0]='f') and (tok_id[1]='u') and (tok_id[2]='n') then classify_ident := TK_FUN
142	    else if (tok_id[0]='n') and (tok_id[1]='o') and (tok_id[2]='t') then classify_ident := TK_NOT
143	    else if (tok_id[0]='m') and (tok_id[1]='o') and (tok_id[2]='d') then classify_ident := TK_MOD
144	  end else if tok_id_len = 4 then begin
145	    if (tok_id[0]='t') and (tok_id[1]='h') and (tok_id[2]='e') and (tok_id[3]='n') then classify_ident := TK_THEN
146	    else if (tok_id[0]='e') and (tok_id[1]='l') and (tok_id[2]='s') and (tok_id[3]='e') then classify_ident := TK_ELSE
147	    else if (tok_id[0]='t') and (tok_id[1]='r') and (tok_id[2]='u') and (tok_id[3]='e') then classify_ident := TK_TRUE
148	    else if (tok_id[0]='w') and (tok_id[1]='i') and (tok_id[2]='t') and (tok_id[3]='h') then classify_ident := TK_WITH
149	  end else if tok_id_len = 5 then begin
150	    if (tok_id[0]='f') and (tok_id[1]='a') and (tok_id[2]='l') and (tok_id[3]='s') and (tok_id[4]='e') then classify_ident := TK_FALSE
151	    else if (tok_id[0]='m') and (tok_id[1]='a') and (tok_id[2]='t') and (tok_id[3]='c') and (tok_id[4]='h') then classify_ident := TK_MATCH
152	  end else if tok_id_len = 8 then begin
153	    if (tok_id[0]='f') and (tok_id[1]='u') and (tok_id[2]='n') and (tok_id[3]='c')
154	      and (tok_id[4]='t') and (tok_id[5]='i') and (tok_id[6]='o') and (tok_id[7]='n') then classify_ident := TK_FUNCTION
155	  end end;
156	procedure crlf;
157	begin write(chr(13)); write(chr(10)) end;
158	
159	procedure lex_init;
160	{ Read one line from UART (until newline or EOT). Echoes each char
161	  for interactive terminal use. Resets lexer state.
162	
163	  Handles backspace (chr(8) or chr(127)) by removing the last char
164	  and visually backing up the cursor. }
165	begin src_len := 0; pos := 0; tok := TK_EOF; tok_int := 0; tok_id_len := 0;
166	  while not eof do begin
167	    read(ch);
168	    if ch = chr(4) then exit;
169	    if (ch = chr(8)) or (ch = chr(127)) then begin
170	      if src_len > 0 then begin
171	        src_len := src_len - 1;
172	        write(chr(8)); write(' '); write(chr(8))
173	      end
174	    end
175	    else begin
176	      write(ch);  { echo the character }
177	      if (ch = chr(13)) or (ch = chr(10)) then begin crlf; exit end;
178	      if src_len < SRC_MAX then begin src[src_len] := ch; src_len := src_len + 1 end
179	    end
180	  end
181	end;
182	procedure lex_next;
183	var c: char;
184	begin skip_ws_and_comments;
185	  if pos >= src_len then begin tok := TK_EOF; exit end;
186	  c := src[pos];
187	  if is_digit(c) then begin tok := TK_INT; tok_int := 0;
188	    while (pos < src_len) and is_digit(src[pos]) do begin tok_int := tok_int*10 + (ord(src[pos])-ord('0')); pos := pos+1 end; exit end;
189	  if is_alpha(c) then begin tok_id_len := 0;
190	    while (pos < src_len) and is_alnum(src[pos]) do begin
191	      if tok_id_len < ID_MAX then begin tok_id[tok_id_len] := src[pos]; tok_id_len := tok_id_len+1 end; pos := pos+1 end;
192	    tok := classify_ident; exit end;
193	  if c = '+' then begin tok := TK_PLUS; pos := pos+1; exit end;
194	  if c = '*' then begin tok := TK_STAR; pos := pos+1; exit end;
195	  if c = '/' then begin tok := TK_SLASH; pos := pos+1; exit end;
196	  if c = '(' then begin tok := TK_LPAREN; pos := pos+1; exit end;
197	  if c = ')' then begin tok := TK_RPAREN; pos := pos+1; exit end;
198	  if c = ';' then begin tok := TK_SEMI; pos := pos+1; exit end;
199	  if c = '[' then begin tok := TK_LBRACKET; pos := pos+1; exit end;
200	  if c = '.' then begin tok := TK_DOT; pos := pos+1; exit end;
201	  if c = ',' then begin tok := TK_COMMA; pos := pos+1; exit end;
202	  if c = '^' then begin tok := TK_CARET; pos := pos+1; exit end;
203	  if c = '"' then begin
204	    { String literal. Read until closing quote, handling escapes. }
205	    pos := pos + 1;
206	    tok_str_off := string_pool_len;
207	    tok_str_len := 0;
208	    while (pos < src_len) and (src[pos] <> '"') do begin
209	      if src[pos] = '\' then begin
210	        pos := pos + 1;
211	        if pos >= src_len then begin tok := TK_ERROR; exit end;
212	        if src[pos] = 'n' then begin
213	          if string_pool_len < 4095 then begin string_pool[string_pool_len] := chr(10); string_pool_len := string_pool_len+1; tok_str_len := tok_str_len+1 end
214	        end else if src[pos] = 't' then begin
215	          if string_pool_len < 4095 then begin string_pool[string_pool_len] := chr(9); string_pool_len := string_pool_len+1; tok_str_len := tok_str_len+1 end
216	        end else if src[pos] = '"' then begin
217	          if string_pool_len < 4095 then begin string_pool[string_pool_len] := '"'; string_pool_len := string_pool_len+1; tok_str_len := tok_str_len+1 end
218	        end else if src[pos] = '\' then begin
219	          if string_pool_len < 4095 then begin string_pool[string_pool_len] := '\'; string_pool_len := string_pool_len+1; tok_str_len := tok_str_len+1 end
220	        end else begin
221	          { unknown escape: pass through the char as-is }
222	          if string_pool_len < 4095 then begin string_pool[string_pool_len] := src[pos]; string_pool_len := string_pool_len+1; tok_str_len := tok_str_len+1 end
223	        end;
224	        pos := pos + 1
225	      end else begin
226	        if string_pool_len < 4095 then begin string_pool[string_pool_len] := src[pos]; string_pool_len := string_pool_len+1; tok_str_len := tok_str_len+1 end;
227	        pos := pos + 1
228	      end
229	    end;
230	    if (pos < src_len) and (src[pos] = '"') then pos := pos + 1
231	    else begin tok := TK_ERROR; exit end;
232	    tok := TK_STRING;
233	    exit
234	  end;
235	  if c = ']' then begin tok := TK_RBRACKET; pos := pos+1; exit end;
236	  if c = ':' then begin
237	    pos := pos+1;
238	    if (pos < src_len) and (src[pos] = ':') then begin tok := TK_COLONCOLON; pos := pos+1 end
239	    else tok := TK_ERROR;
240	    exit
241	  end;
242	  if c = '=' then begin tok := TK_EQ; pos := pos+1; exit end;
243	  if c = '-' then begin pos := pos+1;
244	    if (pos < src_len) and (src[pos] = '>') then begin tok := TK_ARROW; pos := pos+1 end else tok := TK_MINUS; exit end;
245	  if c = '<' then begin pos := pos+1;
246	    if (pos < src_len) and (src[pos] = '>') then begin tok := TK_NEQ; pos := pos+1 end
247	    else if (pos < src_len) and (src[pos] = '=') then begin tok := TK_LE; pos := pos+1 end
248	    else tok := TK_LT; exit end;
249	  if c = '>' then begin pos := pos+1;
250	    if (pos < src_len) and (src[pos] = '=') then begin tok := TK_GE; pos := pos+1 end else tok := TK_GT; exit end;
251	  if c = '&' then begin pos := pos+1;
252	    if (pos < src_len) and (src[pos] = '&') then begin tok := TK_ANDAND; pos := pos+1 end else tok := TK_ERROR; exit end;
253	  if c = '|' then begin pos := pos+1;
254	    if (pos < src_len) and (src[pos] = '|') then begin tok := TK_OROR; pos := pos+1 end else tok := TK_PIPE; exit end;
255	  tok := TK_ERROR; pos := pos+1 end;
