354	function is_atom_start: boolean;
355	begin is_atom_start := (tok=TK_INT) or (tok=TK_TRUE) or (tok=TK_FALSE) or (tok=TK_IDENT) or (tok=TK_LPAREN) or (tok=TK_LBRACKET) or (tok=TK_STRING) end;
356	function parse_atom: PExpr;
357	var e: PExpr; i: integer;
358	begin parse_atom := nil;
359	  if tok=TK_INT then begin parse_atom := mk_int(tok_int); lex_next; exit end;
360	  if tok=TK_TRUE then begin parse_atom := mk_bool(1); lex_next; exit end;
361	  if tok=TK_FALSE then begin parse_atom := mk_bool(0); lex_next; exit end;
362	  if tok=TK_STRING then begin parse_atom := mk_string_expr(tok_str_off, tok_str_len); lex_next; exit end;
363	  if tok=TK_IDENT then begin
364	    { Create EK_VAR for the current ident first (tok_id still has it). }
365	    e := mk_var_node;
366	    lex_next;
367	    { If followed by one or more '.ident', extend the name in the
368	      already-created node by appending '.' + ident to the name pool.
369	      Works because pool_intern writes contiguously and no other
370	      interns happen between mk_var_node and here. }
371	    while tok = TK_DOT do begin
372	      lex_next;
373	      if tok <> TK_IDENT then begin parse_error := true; exit end;
374	      if name_pool_len < NAME_POOL_MAX then begin
375	        name_pool[name_pool_len] := '.';
376	        name_pool_len := name_pool_len + 1;
377	        e^.nlen := e^.nlen + 1
378	      end;
379	      i := 0;
380	      while i < tok_id_len do begin
381	        if name_pool_len < NAME_POOL_MAX then begin
382	          name_pool[name_pool_len] := tok_id[i];
383	          name_pool_len := name_pool_len + 1;
384	          e^.nlen := e^.nlen + 1
385	        end;
386	        i := i + 1
387	      end;
388	      lex_next
389	    end;
390	    parse_atom := e;
391	    exit
392	  end;
393	  if tok=TK_LPAREN then begin lex_next;
394	    if tok=TK_RPAREN then begin parse_atom := mk_int(0); lex_next; exit end;
395	    e := parse_seq;
396	    if tok=TK_COMMA then begin
397	      lex_next;
398	      e := mk_binop(OP_PAIR, e, parse_expr);
399	      if tok=TK_RPAREN then lex_next else parse_error := true
