1053	function try_match(p: PPat; v: PVal; env: PEnv): PEnv;
1054	{ Attempts to match pattern p against value v, extending env.
1055	  Sets match_success := true on success, false on fail.
1056	  Returns extended env on success (or env unchanged if no bindings). }
1057	var e1: PEnv;
1058	begin
1059	  try_match := env;
1060	  match_success := true;
1061	  if p = nil then begin match_success := false; exit end;
1062	  if v = nil then begin match_success := false; exit end;
1063	
1064	  if p^.pk = PK_WILDCARD then exit;
1065	
1066	  if p^.pk = PK_VAR then begin
1067	    try_match := env_extend(env, p^.noff, p^.nlen, v);
1068	    exit
1069	  end;
1070	
1071	  if p^.pk = PK_INT then begin
1072	    if (v^.vk = VK_INT) and (v^.ival = p^.ival) then exit;
1073	    match_success := false; exit
1074	  end;
1075	
1076	  if p^.pk = PK_BOOL then begin
1077	    if (v^.vk = VK_BOOL) and (v^.ival = p^.ival) then exit;
1078	    match_success := false; exit
1079	  end;
1080	
1081	  if p^.pk = PK_NIL then begin
1082	    if v^.vk = VK_NIL then exit;
1083	    match_success := false; exit
1084	  end;
1085	
1086	  if p^.pk = PK_CONS then begin
1087	    if v^.vk <> VK_CONS then begin match_success := false; exit end;
1088	    e1 := try_match(p^.sub1, v^.head, env);
1089	    if not match_success then exit;
1090	    try_match := try_match(p^.sub2, v^.tail, e1);
1091	    exit
1092	  end;
1093	
1094	  if p^.pk = PK_PAIR then begin
1095	    if v^.vk <> VK_PAIR then begin match_success := false; exit end;
1096	    e1 := try_match(p^.sub1, v^.head, env);
1097	    if not match_success then exit;
1098	    try_match := try_match(p^.sub2, v^.tail, e1);
1099	    exit
1100	  end;
1101	
1102	  if p^.pk = PK_NONE then begin
1103	    if v^.vk = VK_NONE then exit;
1104	    match_success := false; exit
1105	  end;
1106	
1107	  if p^.pk = PK_SOME then begin
1108	    if v^.vk <> VK_SOME then begin match_success := false; exit end;
1109	    try_match := try_match(p^.sub1, v^.head, env);
1110	    exit
1111	  end;
1112	
1113	  match_success := false
1114	end;
