{ Constructor registry helpers.
  Tags are global indices into ctor_names_off/ctor_names_len so that
  constructors from different types never collide in pattern matching. }
function ctor_lookup_tok: integer;
var i, j: integer; eq: boolean;
begin ctor_lookup_tok := -1;
  i := 0;
  while i < ctor_count do begin
    if ctor_names_len[i] = tok_id_len then begin
      eq := true; j := 0;
      while (j < tok_id_len) and eq do begin
        if name_pool[ctor_names_off[i] + j] <> tok_id[j] then eq := false;
        j := j + 1
      end;
      if eq then begin ctor_lookup_tok := i; exit end
    end;
    i := i + 1
  end
end;
function ctor_lookup_pool(noff, nlen: integer): integer;
var i, j: integer; eq: boolean;
begin ctor_lookup_pool := -1;
